clear;x = [0,1,2, 2,-1,1,0];y = [0,2,1,-1, 0,0,0];n = [0,1,2, 3, 4,5,6];z = conv(x,y); # this assumes both x and y start at n = 0...they may not# so be careful about how things are aligned temporally# without the "same" parameter conv() returns the zero-padded result# where length(z) = length(x) + length(y) - 1# z = conv(x,y,'same'); # just the central part of the convolution# you'll see that z is longer than x and y due to the sliding, multiplying and summingfigure(1);clf();plt= subplot(3,1,1);stem(n, x, "linewidth", 2);axis([0 length(x) (min(x)-1) (max(x)+1)]); # set the axes limits ([xlo xhi ylo yhi])set(gca, "linewidth", 2, "fontsize", 14)#grid on;title("x[n]");subplot(3,1,2);stem(n, y, "linewidth", 2);axis([0 length(y) (min(y)-1) (max(y)+1)]); # set the axes limits ([xlo xhi ylo yhi])set(gca, "linewidth", 2, "fontsize", 14)#grid on;title("y[n]");subplot(3,1,3);stem([0:1:(length(z)-1)], z, "linewidth", 2);axis([0 length(z)-1 (min(z)-1) (max(z)+1)]); # set the axes limits ([xlo xhi ylo yhi])set(gca, "linewidth", 2, "fontsize", 14);#grid on;title("z[n]");